<?php $editing=!empty($product);?><div class="page-heading"><div><span class="eyebrow">PRODUCTOS</span><h2><?=$editing?'Editar producto':'Registrar producto'?></h2><p>Información comercial y parámetros de control de stock.</p></div><a class="btn btn-light" href="index.php?route=productos"><i class="bi bi-arrow-left me-2"></i>Volver</a></div><form method="post" action="index.php?route=productos/guardar"><input type="hidden" name="csrf_token" value="<?=App\Helpers\Csrf::token()?>"><input type="hidden" name="id" value="<?=$product['IdProducto']??0?>"><div class="form-layout"><section class="panel"><div class="panel-header"><div><h3>Información general</h3><p>Datos de identificación del producto.</p></div></div><div class="form-grid"><label>Código interno<input class="form-control" name="codigo" required maxlength="50" value="<?=htmlspecialchars($product['Codigo']??'')?>"></label><label>Código de barras<input class="form-control" name="barras" maxlength="80" value="<?=htmlspecialchars($product['CodigoBarras']??'')?>"></label><label class="full">Nombre<input class="form-control" name="nombre" required maxlength="150" value="<?=htmlspecialchars($product['Nombre']??'')?>"></label><label class="full">Descripción<textarea class="form-control" name="descripcion" rows="4"><?=htmlspecialchars($product['Descripcion']??'')?></textarea></label></div></section><section class="panel"><div class="panel-header"><div><h3>Clasificación y compra</h3><p>Relaciones comerciales del producto.</p></div></div><div class="form-grid"><label>Categoría<select class="form-select" name="categoria" required><?php foreach($catalogs['categories'] as $c):?><option value="<?=$c['IdCategoria']?>" <?=($product['IdCategoria']??0)==$c['IdCategoria']?'selected':''?>><?=htmlspecialchars($c['Nombre'])?></option><?php endforeach;?></select></label><label>Unidad<select class="form-select" name="unidad" required><?php foreach($catalogs['units'] as $u):?><option value="<?=$u['IdUnidad']?>" <?=($product['IdUnidad']??0)==$u['IdUnidad']?'selected':''?>><?=htmlspecialchars($u['Nombre'])?></option><?php endforeach;?></select></label><label>Marca<select class="form-select" name="marca"><option value="0">Sin marca</option><?php foreach($catalogs['brands'] as $m):?><option value="<?=$m['IdMarca']?>" <?=($product['IdMarca']??0)==$m['IdMarca']?'selected':''?>><?=htmlspecialchars($m['Nombre'])?></option><?php endforeach;?></select></label><label>Proveedor<select class="form-select" name="proveedor"><option value="0">Sin proveedor</option><?php foreach($catalogs['suppliers'] as $s):?><option value="<?=$s['IdProveedor']?>" <?=($product['IdProveedor']??0)==$s['IdProveedor']?'selected':''?>><?=htmlspecialchars($s['RazonSocial'])?></option><?php endforeach;?></select></label><label>Precio compra<input class="form-control" type="number" step="0.01" min="0" name="compra" value="<?=$product['PrecioCompra']??0?>"></label><label>Precio venta<input class="form-control" type="number" step="0.01" min="0" name="venta" value="<?=$product['PrecioVenta']??0?>"></label></div></section><section class="panel full-span"><div class="panel-header"><div><h3>Política de inventario</h3><p>Límites para alertas y reposición.</p></div></div><div class="form-grid four"><label>Stock mínimo<input class="form-control" type="number" step="0.01" min="0" name="minimo" value="<?=$product['StockMinimo']??0?>"></label><label>Stock máximo<input class="form-control" type="number" step="0.01" min="0" name="maximo" value="<?=$product['StockMaximo']??0?>"></label><div class="form-note"><i class="bi bi-info-circle"></i><span>El stock actual se modifica únicamente mediante entradas y salidas.</span></div><div class="text-end align-self-end"><button class="btn btn-primary btn-lg"><i class="bi bi-check2-circle me-2"></i>Guardar producto</button></div></div></section></div></form>